ALTER TABLE "coinflip_challenges" ADD CONSTRAINT "coinflip_challenges_distinct_members_check" CHECK ("coinflip_challenges"."challenger_id" <> "coinflip_challenges"."opponent_id");--> statement-breakpoint
ALTER TABLE "coinflip_challenges" ADD CONSTRAINT "coinflip_challenges_positive_wager_check" CHECK ("coinflip_challenges"."wager" > 0);--> statement-breakpoint
ALTER TABLE "coinflip_challenges" ADD CONSTRAINT "coinflip_challenges_winner_check" CHECK ("coinflip_challenges"."winner_id" is null or "coinflip_challenges"."winner_id" in ("coinflip_challenges"."challenger_id", "coinflip_challenges"."opponent_id"));--> statement-breakpoint
ALTER TABLE "coinflip_challenges" ADD CONSTRAINT "coinflip_challenges_resolution_check" CHECK (("coinflip_challenges"."status" = 'pending' and "coinflip_challenges"."outcome" is null and "coinflip_challenges"."winner_id" is null and "coinflip_challenges"."resolved_at" is null) or ("coinflip_challenges"."status" = 'completed' and "coinflip_challenges"."outcome" is not null and "coinflip_challenges"."winner_id" is not null and "coinflip_challenges"."resolved_at" is not null) or ("coinflip_challenges"."status" in ('declined', 'expired') and "coinflip_challenges"."outcome" is null and "coinflip_challenges"."winner_id" is null and "coinflip_challenges"."resolved_at" is not null));